import threading
import time
import uuid
from datetime import datetime, timedelta
from typing import Dict, Optional, Tuple

class ATMSystem:
    def __init__(self):
        self.accounts: Dict[str, float] = {}  # account_id: balance
        self.locks: Dict[str, threading.Lock] = {}  # account_id: lock
        self.failed_attempts: Dict[str, int] = {}  # account_id: failed attempts
        self.last_attempt_time: Dict[str, datetime] = {}  # account_id: last attempt time
        self.transaction_ids: Dict[str, str] = {}  # transaction_id: account_id
        self.global_lock = threading.Lock()  # For account creation and global operations

    def create_account(self, account_id: str, initial_balance: float = 0.0) -> bool:
        with self.global_lock:
            if account_id in self.accounts:
                return False
            self.accounts[account_id] = initial_balance
            self.locks[account_id] = threading.Lock()
            self.failed_attempts[account_id] = 0
            self.last_attempt_time[account_id] = datetime.min
            return True

    def _check_security(self, account_id: str) -> bool:
        """Check if account is locked due to too many failed attempts"""
        if self.failed_attempts.get(account_id, 0) >= 3:
            last_attempt = self.last_attempt_time.get(account_id, datetime.min)
            if datetime.now() - last_attempt < timedelta(minutes=5):
                return False
            else:
                # Reset after timeout
                self.failed_attempts[account_id] = 0
        return True

    def _record_failed_attempt(self, account_id: str):
        """Record a failed attempt and potentially lock the account"""
        self.failed_attempts[account_id] = self.failed_attempts.get(account_id, 0) + 1
        self.last_attempt_time[account_id] = datetime.now()

    def begin_transaction(self, account_id: str) -> Optional[str]:
        """Start a transaction and return a transaction ID"""
        if account_id not in self.accounts:
            return None

        if not self._check_security(account_id):
            return None

        transaction_id = str(uuid.uuid4())
        with self.global_lock:
            self.transaction_ids[transaction_id] = account_id
        return transaction_id

    def _verify_transaction(self, transaction_id: str) -> Optional[str]:
        """Verify transaction and return account_id if valid"""
        with self.global_lock:
            account_id = self.transaction_ids.get(transaction_id)
            if not account_id:
                return None
            return account_id

    def deposit(self, transaction_id: str, amount: float) -> bool:
        account_id = self._verify_transaction(transaction_id)
        if not account_id or amount <= 0:
            return False

        with self.locks[account_id]:
            self.accounts[account_id] += amount
            return True

    def withdraw(self, transaction_id: str, amount: float) -> bool:
        account_id = self._verify_transaction(transaction_id)
        if not account_id or amount <= 0:
            return False

        with self.locks[account_id]:
            if self.accounts[account_id] >= amount:
                self.accounts[account_id] -= amount
                return True
            else:
                self._record_failed_attempt(account_id)
                return False

    def check_balance(self, transaction_id: str) -> Optional[float]:
        account_id = self._verify_transaction(transaction_id)
        if not account_id:
            return None

        with self.locks[account_id]:
            return self.accounts[account_id]

    def transfer(self, from_transaction_id: str, to_account_id: str, amount: float) -> bool:
        from_account_id = self._verify_transaction(from_transaction_id)
        if not from_account_id or to_account_id not in self.accounts or amount <= 0:
            return False

        # Lock ordering to prevent deadlocks
        lock1, lock2 = sorted([self.locks[from_account_id], self.locks[to_account_id]], key=id)

        with lock1, lock2:
            if self.accounts[from_account_id] >= amount:
                self.accounts[from_account_id] -= amount
                self.accounts[to_account_id] += amount
                return True
            else:
                self._record_failed_attempt(from_account_id)
                return False

    def end_transaction(self, transaction_id: str) -> bool:
        with self.global_lock:
            if transaction_id in self.transaction_ids:
                del self.transaction_ids[transaction_id]
                return True
            return False

    def get_account_status(self, account_id: str) -> Tuple[bool, Optional[bool]]:
        """Returns (account_exists, is_locked)"""
        if account_id not in self.accounts:
            return (False, None)
        return (True, self.failed_attempts.get(account_id, 0) >= 3)

