import threading
import time
import uuid
import hashlib
import logging
from datetime import datetime, timedelta
from typing import Dict, Optional, Tuple

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("ATMController")

class ATMSystem:
    def __init__(self):
        self.lock = threading.Lock()
        self.accounts: Dict[str, Dict[str, float]] = {}  # account_id: {balance, ...}
        self.sessions: Dict[str, Dict[str, str]] = {}  # session_id: {account_id, expiry}
        self.transactions: Dict[str, Dict[str, str]] = {}  # transaction_id: {account_id, status, amount}
        self.failed_attempts: Dict[str, int] = {}  # account_id: count
        self.card_blocklist: set = set()

    def _generate_session_id(self, account_id: str) -> str:
        return hashlib.sha256(f"{account_id}{time.time()}".encode()).hexdigest()

    def _generate_transaction_id(self) -> str:
        return str(uuid.uuid4())

    def _validate_pin(self, account_id: str, pin: str) -> bool:
        # In a real system, this would verify against hashed PIN
        return True  # Placeholder

    def _check_account_lock(self, account_id: str) -> bool:
        if self.failed_attempts.get(account_id, 0) >= 3:
            logger.warning(f"Account {account_id} is locked due to too many failed attempts")
            return False
        return True

    def authenticate(self, card_number: str, pin: str) -> Optional[str]:
        if card_number in self.card_blocklist:
            logger.warning(f"Blocked card attempt: {card_number}")
            return None

        account_id = self._get_account_from_card(card_number)
        if not account_id:
            return None

        with self.lock:
            if not self._check_account_lock(account_id):
                return None

            if not self._validate_pin(account_id, pin):
                self.failed_attempts[account_id] = self.failed_attempts.get(account_id, 0) + 1
                logger.warning(f"Failed login attempt for account {account_id}")
                return None

            # Reset failed attempts on successful login
            self.failed_attempts.pop(account_id, None)

            session_id = self._generate_session_id(account_id)
            expiry = datetime.now() + timedelta(minutes=5)
            self.sessions[session_id] = {
                'account_id': account_id,
                'expiry': expiry.isoformat()
            }
            return session_id

    def _get_account_from_card(self, card_number: str) -> Optional[str]:
        # In a real system, this would map card to account
        return f"account_{card_number[-4:]}"  # Placeholder

    def validate_session(self, session_id: str) -> Optional[str]:
        with self.lock:
            session = self.sessions.get(session_id)
            if not session:
                return None

            if datetime.fromisoformat(session['expiry']) < datetime.now():
                self.sessions.pop(session_id, None)
                return None

            # Extend session
            new_expiry = datetime.now() + timedelta(minutes=5)
            session['expiry'] = new_expiry.isoformat()
            return session['account_id']

    def get_balance(self, session_id: str) -> Optional[float]:
        account_id = self.validate_session(session_id)
        if not account_id:
            return None

        with self.lock:
            account = self.accounts.get(account_id)
            if not account:
                return None
            return account.get('balance', 0.0)

    def _check_transaction_limit(self, account_id: str, amount: float) -> bool:
        # Example limit check
        return amount <= 1000.0  # Placeholder limit

    def withdraw(self, session_id: str, amount: float) -> Tuple[bool, Optional[str]]:
        account_id = self.validate_session(session_id)
        if not account_id:
            return False, "Invalid session"

        if amount <= 0:
            return False, "Invalid amount"

        with self.lock:
            if not self._check_transaction_limit(account_id, amount):
                return False, "Transaction limit exceeded"

            account = self.accounts.get(account_id)
            if not account:
                return False, "Account not found"

            if account['balance'] < amount:
                return False, "Insufficient funds"

            transaction_id = self._generate_transaction_id()
            self.transactions[transaction_id] = {
                'account_id': account_id,
                'amount': amount,
                'status': 'pending',
                'timestamp': datetime.now().isoformat()
            }

            try:
                # Simulate network delay
                time.sleep(0.1)
                account['balance'] -= amount
                self.transactions[transaction_id]['status'] = 'completed'
                logger.info(f"Withdrawal of {amount} from {account_id} completed")
                return True, transaction_id
            except Exception as e:
                self.transactions[transaction_id]['status'] = 'failed'
                logger.error(f"Withdrawal failed: {str(e)}")
                return False, "Transaction failed"

    def deposit(self, session_id: str, amount: float) -> Tuple[bool, Optional[str]]:
        account_id = self.validate_session(session_id)
        if not account_id:
            return False, "Invalid session"

        if amount <= 0:
            return False, "Invalid amount"

        with self.lock:
            account = self.accounts.get(account_id)
            if not account:
                return False, "Account not found"

            transaction_id = self._generate_transaction_id()
            self.transactions[transaction_id] = {
                'account_id': account_id,
                'amount': amount,
                'status': 'pending',
                'timestamp': datetime.now().isoformat()
            }

            try:
                # Simulate cash validation delay
                time.sleep(0.2)
                account['balance'] += amount
                self.transactions[transaction_id]['status'] = 'completed'
                logger.info(f"Deposit of {amount} to {account_id} completed")
                return True, transaction_id
            except Exception as e:
                self.transactions[transaction_id]['status'] = 'failed'
                logger.error(f"Deposit failed: {str(e)}")
                return False, "Transaction failed"

    def transfer(self, session_id: str, target_account: str, amount: float) -> Tuple[bool, Optional[str]]:
        source_account = self.validate_session(session_id)
        if not source_account:
            return False, "Invalid session"

        if amount <= 0:
            return False, "Invalid amount"

        with self.lock:
            if not self._check_transaction_limit(source_account, amount):
                return False, "Transaction limit exceeded"

            source = self.accounts.get(source_account)
            target = self.accounts.get(target_account)
            if not source or not target:
                return False, "Account not found"

            if source['balance'] < amount:
                return False, "Insufficient funds"

            transaction_id = self._generate_transaction_id()
            self.transactions[transaction_id] = {
                'account_id': source_account,
                'target_account': target_account,
                'amount': amount,
                'status': 'pending',
                'timestamp': datetime.now().isoformat()
            }

            try:
                # Simulate transfer processing
                time.sleep(0.15)
                source['balance'] -= amount
                target['balance'] += amount
                self.transactions[transaction_id]['status'] = 'completed'
                logger.info(f"Transfer of {amount} from {source_account} to {target_account} completed")
                return True, transaction_id
            except Exception as e:
                self.transactions[transaction_id]['status'] = 'failed'
                logger.error(f"Transfer failed: {str(e)}")
                return False, "Transaction failed"

    def logout(self, session_id: str) -> bool:
        with self.lock:
            if session_id in self.sessions:
                self.sessions.pop(session_id)
                return True
            return False

    def block_card(self, card_number: str) -> None:
        with self.lock:
            self.card_blocklist.add(card_number)
            logger.info(f"Card {card_number} blocked")

    def add_account(self, account_id: str, initial_balance: float = 0.0) -> None:
        with self.lock:
            self.accounts[account_id] = {'balance': initial_balance}

